const input = $input.first().json || {};
const headers = input.headers || {};

const SUPABASE_URL = String(input.supabaseUrl || $env.SUPABASE_URL || '').trim();
const SUPABASE_SERVICE_ROLE_KEY = String(input.supabaseServiceRoleKey || $env.SUPABASE_SERVICE_ROLE_KEY || '').trim();
const TELEGRAM_BOT_TOKEN = String(input.telegramBotToken || $env.TELEGRAM_BOT_TOKEN || '').trim();
const SECRET_EXPECTED = String(input.notifyWebhookSecret || $env.N8N_NOTIFY_WEBHOOK_SECRET || '').trim();
const SECRET_RECEIVED = String(headers['x-notify-secret'] || headers['X-Notify-Secret'] || '').trim();
const LOOKBACK_MINUTES = Number(input.lookbackMinutes || 6);
const waitSecondsRaw = Number(input.regularWaveWaitSeconds || 75);
const WAIT_SECONDS = Number.isFinite(waitSecondsRaw) ? Math.max(10, Math.min(110, waitSecondsRaw)) : 75;
const PUBLIC_BASE_URL = String(input.publicBaseUrl || $env.APP_BASE_URL || 'https://cargadores-aspe.onlineexpansions.com').replace(/\/+$/, '');

if (!SUPABASE_URL || !SUPABASE_SERVICE_ROLE_KEY) throw new Error('Faltan credenciales de Supabase');
if (!TELEGRAM_BOT_TOKEN) throw new Error('Falta TELEGRAM_BOT_TOKEN');
if (SECRET_EXPECTED && SECRET_EXPECTED !== SECRET_RECEIVED) throw new Error('Webhook secret invalido');

async function requestText(url, options) {
  if (typeof fetch === 'function') {
    const response = await fetch(url, options);
    const body = await response.text();
    return { ok: response.ok, status: response.status, body: body };
  }
  const helper = this && this.helpers && this.helpers.httpRequest;
  if (typeof helper !== 'function') throw new Error('fetch no disponible en este nodo de n8n');
  const response = await helper({
    url: url,
    method: options.method || 'GET',
    headers: options.headers,
    body: options.body,
    json: false,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true
  });
  return {
    ok: response.statusCode >= 200 && response.statusCode < 300,
    status: response.statusCode,
    body: typeof response.body === 'string' ? response.body : JSON.stringify(response.body || '')
  };
}

function supabaseHeaders(prefer) {
  const headersOut = {
    apikey: SUPABASE_SERVICE_ROLE_KEY,
    Authorization: 'Bearer ' + SUPABASE_SERVICE_ROLE_KEY,
    'Content-Type': 'application/json'
  };
  if (prefer) headersOut.Prefer = prefer;
  return headersOut;
}

async function supabaseGet(path) {
  const response = await requestText.call(this, SUPABASE_URL + '/rest/v1/' + path, { method: 'GET', headers: supabaseHeaders() });
  if (!response.ok) throw new Error('Supabase GET fallo: ' + path + ' -> ' + response.status + ' ' + response.body);
  return response.body ? JSON.parse(response.body) : [];
}

async function supabasePost(path, payload, prefer) {
  const response = await requestText.call(this, SUPABASE_URL + '/rest/v1/' + path, { method: 'POST', headers: supabaseHeaders(prefer), body: JSON.stringify(payload) });
  if (!response.ok) throw new Error('Supabase POST fallo: ' + path + ' -> ' + response.status + ' ' + response.body);
  return response.body ? JSON.parse(response.body) : [];
}

async function supabasePatch(path, payload) {
  const response = await requestText.call(this, SUPABASE_URL + '/rest/v1/' + path, { method: 'PATCH', headers: supabaseHeaders('return=minimal'), body: JSON.stringify(payload) });
  if (!response.ok) throw new Error('Supabase PATCH fallo: ' + path + ' -> ' + response.status + ' ' + response.body);
}

async function sendTelegram(chatId, text) {
  const response = await requestText.call(this, 'https://api.telegram.org/bot' + TELEGRAM_BOT_TOKEN + '/sendMessage', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ chat_id: String(chatId), text: text, disable_web_page_preview: true })
  });
  if (!response.ok) throw new Error('Telegram sendMessage fallo: ' + response.status + ' ' + response.body);
}

function buildMessage(eventItem) {
  return '🔔 Cargador libre ahora\n' + eventItem.locationName + '\n\nVer estado: ' + PUBLIC_BASE_URL + '/charger/' + encodeURIComponent(eventItem.stationId);
}

function markPatch(sub) {
  const nowIso = new Date().toISOString();
  return sub.notify_mode === 'first_only' ? { last_notified_at: nowIso, active: false } : { last_notified_at: nowIso };
}

const lookbackIso = new Date(Date.now() - LOOKBACK_MINUTES * 60 * 1000).toISOString();
const logs = await supabaseGet.call(this, 'charging_logs?select=id,created_at,station_id,location_name,is_available&created_at=gt.' + encodeURIComponent(lookbackIso) + '&order=station_id.asc,created_at.desc&limit=500');

const byStation = new Map();
for (const row of logs) {
  const list = byStation.get(row.station_id) || [];
  if (list.length < 2) list.push(row);
  byStation.set(row.station_id, list);
}

const freeEvents = [];
for (const pair of byStation.values()) {
  if (pair.length < 2) continue;
  const current = pair[0];
  const previous = pair[1];
  if (!previous.is_available && current.is_available) {
    freeEvents.push({
      stationId: current.station_id,
      locationName: current.location_name,
      eventKey: 'libre_ahora:' + current.station_id + ':' + current.created_at
    });
  }
}

if (!freeEvents.length) {
  return [{ json: { ok: true, info: 'Sin eventos de liberacion en esta ventana', waitSeconds: WAIT_SECONDS, pendingRegular: [] } }];
}

const nowIso = new Date().toISOString();
const pendingRegular = [];
const sentPremium = [];
const skipped = [];

for (const eventItem of freeEvents) {
  const subsPath = 'notification_subscriptions?select=id,user_id,notify_mode,cooldown_minutes,last_notified_at,user:telegram_users(telegram_user_id,telegram_chat_id,telegram_username,is_premium,is_active)&active=eq.true&station_id=eq.' + encodeURIComponent(eventItem.stationId) + '&expires_at=gt.' + encodeURIComponent(nowIso) + '&limit=500';
  const subscriptions = await supabaseGet.call(this, subsPath);

  for (const sub of subscriptions) {
    const user = sub.user || {};
    const chatId = user.telegram_chat_id ? String(user.telegram_chat_id) : '';

    if (!user.is_active || !chatId) {
      skipped.push({ reason: 'usuario_inactivo_o_sin_chat_id', subscriptionId: sub.id, stationId: eventItem.stationId });
      continue;
    }

    if (sub.last_notified_at) {
      const cooldownMs = Number(sub.cooldown_minutes || 30) * 60 * 1000;
      const lastMs = new Date(sub.last_notified_at).getTime();
      if (Number.isFinite(lastMs) && Date.now() - lastMs < cooldownMs) {
        skipped.push({ reason: 'cooldown_activo', subscriptionId: sub.id, stationId: eventItem.stationId });
        continue;
      }
    }

    if (user.is_premium) {
      const inserted = await supabasePost.call(this, 'notification_dispatches?on_conflict=subscription_id,event_key,wave', [{ subscription_id: sub.id, event_key: eventItem.eventKey, wave: 'priority' }], 'resolution=ignore-duplicates,return=representation');
      if (!Array.isArray(inserted) || !inserted.length) {
        skipped.push({ reason: 'dispatch_premium_duplicado', subscriptionId: sub.id, stationId: eventItem.stationId });
        continue;
      }
      await sendTelegram.call(this, chatId, buildMessage(eventItem));
      await supabasePatch.call(this, 'notification_subscriptions?id=eq.' + encodeURIComponent(sub.id), markPatch(sub));
      sentPremium.push({ subscriptionId: sub.id, stationId: eventItem.stationId, telegramUserId: user.telegram_user_id ? String(user.telegram_user_id) : null });
      continue;
    }

    pendingRegular.push({
      subscriptionId: sub.id,
      stationId: eventItem.stationId,
      locationName: eventItem.locationName,
      eventKey: eventItem.eventKey,
      telegramChatId: chatId,
      notifyMode: sub.notify_mode
    });
  }
}

return [{ json: { ok: true, waitSeconds: WAIT_SECONDS, sentPremiumCount: sentPremium.length, pendingRegular: pendingRegular, skipped: skipped } }];

const input = $input.first().json || {};
const pendingRegular = Array.isArray(input.pendingRegular) ? input.pendingRegular : [];
if (!pendingRegular.length) return [{ json: { ok: true, sentRegularCount: 0, info: 'No hay pendientes para ola regular' } }];

const config = $('Configuracion').first().json || {};
const SUPABASE_URL = String(config.supabaseUrl || $env.SUPABASE_URL || '').trim();
const SUPABASE_SERVICE_ROLE_KEY = String(config.supabaseServiceRoleKey || $env.SUPABASE_SERVICE_ROLE_KEY || '').trim();
const TELEGRAM_BOT_TOKEN = String(config.telegramBotToken || $env.TELEGRAM_BOT_TOKEN || '').trim();
const PUBLIC_BASE_URL = String(config.publicBaseUrl || $env.APP_BASE_URL || 'https://cargadores-aspe.onlineexpansions.com').replace(/\/+$/, '');

if (!SUPABASE_URL || !SUPABASE_SERVICE_ROLE_KEY || !TELEGRAM_BOT_TOKEN) throw new Error('Faltan variables para ola regular');

async function requestText(url, options) {
  if (typeof fetch === 'function') {
    const response = await fetch(url, options);
    const body = await response.text();
    return { ok: response.ok, status: response.status, body: body };
  }
  const helper = this && this.helpers && this.helpers.httpRequest;
  if (typeof helper !== 'function') throw new Error('fetch no disponible en este nodo de n8n');
  const response = await helper({
    url: url,
    method: options.method || 'GET',
    headers: options.headers,
    body: options.body,
    json: false,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true
  });
  return { ok: response.statusCode >= 200 && response.statusCode < 300, status: response.statusCode, body: typeof response.body === 'string' ? response.body : JSON.stringify(response.body || '') };
}

function supabaseHeaders(prefer) {
  const headersOut = { apikey: SUPABASE_SERVICE_ROLE_KEY, Authorization: 'Bearer ' + SUPABASE_SERVICE_ROLE_KEY, 'Content-Type': 'application/json' };
  if (prefer) headersOut.Prefer = prefer;
  return headersOut;
}

async function supabasePatch(path, payload) {
  const response = await requestText.call(this, SUPABASE_URL + '/rest/v1/' + path, { method: 'PATCH', headers: supabaseHeaders('return=minimal'), body: JSON.stringify(payload) });
  if (!response.ok) throw new Error('Supabase PATCH fallo: ' + path + ' -> ' + response.status + ' ' + response.body);
}

async function insertDispatch(subscriptionId, eventKey) {
  const response = await requestText.call(this, SUPABASE_URL + '/rest/v1/notification_dispatches?on_conflict=subscription_id,event_key,wave', {
    method: 'POST',
    headers: supabaseHeaders('resolution=ignore-duplicates,return=representation'),
    body: JSON.stringify([{ subscription_id: subscriptionId, event_key: eventKey, wave: 'regular' }])
  });
  if (!response.ok) throw new Error('No se pudo insertar dispatch regular: HTTP ' + response.status + ' ' + response.body);
  return response.body ? JSON.parse(response.body) : [];
}

async function sendTelegram(chatId, text) {
  const response = await requestText.call(this, 'https://api.telegram.org/bot' + TELEGRAM_BOT_TOKEN + '/sendMessage', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ chat_id: String(chatId), text: text, disable_web_page_preview: true })
  });
  if (!response.ok) throw new Error('Telegram sendMessage regular fallo: HTTP ' + response.status + ' ' + response.body);
}

let sentRegularCount = 0;
const skipped = [];
for (const item of pendingRegular) {
  if (!item.subscriptionId || !item.eventKey || !item.telegramChatId) {
    skipped.push({ reason: 'item_regular_incompleto', item: item });
    continue;
  }

  const inserted = await insertDispatch.call(this, item.subscriptionId, item.eventKey);
  if (!Array.isArray(inserted) || !inserted.length) {
    skipped.push({ reason: 'dispatch_regular_duplicado', subscriptionId: item.subscriptionId, stationId: item.stationId });
    continue;
  }

  const message = '🔔 Cargador libre ahora\n' + item.locationName + '\n\nVer estado: ' + PUBLIC_BASE_URL + '/charger/' + encodeURIComponent(item.stationId);
  await sendTelegram.call(this, item.telegramChatId, message);

  const nowIso = new Date().toISOString();
  const patch = item.notifyMode === 'first_only' ? { last_notified_at: nowIso, active: false } : { last_notified_at: nowIso };
  await supabasePatch.call(this, 'notification_subscriptions?id=eq.' + encodeURIComponent(item.subscriptionId), patch);

  sentRegularCount += 1;
}

return [{ json: { ok: true, sentRegularCount: sentRegularCount, skipped: skipped } }];
